TriggerOraclev10g.body:
DECLARE
    v_user VARCHAR2(255) := coalesce(
        sys_context('APEX$SESSION', 'APP_USER'),
        user
    );
BEGIN
    IF inserting THEN
        :new.created_by := v_user;
        :new.created_on := current_timestamp;
    END IF;

    IF updating THEN
        :new.updated_by := v_user;
        :new.changed_on := current_timestamp;
    END IF;
END;
